280	  // ── Interaction helpers ──────────────────────────────────────────────────────
281	  const getPos = (e: React.MouseEvent) => {
282	    const r = glCanvasRef.current!.getBoundingClientRect();
283	    return { x: e.clientX - r.left, y: e.clientY - r.top };
284	  };
285	
286	  const findNear = (x: number, y: number, r = 14): Site | null => {
287	    let best: Site | null = null, bestD = r;
288	    for (const s of sitesRef.current) {
289	      const d = Math.hypot(s.x - x, s.y - y);
290	      if (d < bestD) { bestD = d; best = s; }
291	    }
292	    return best;
293	  };
294	
295	  // ── Event handlers ───────────────────────────────────────────────────────────
296	  const onMouseDown = useCallback((e: React.MouseEvent<HTMLDivElement>) => {
297	    if (e.button !== 0) return;
298	    const { x, y } = getPos(e);
299	    const near = findNear(x, y);
300	    if (near) {
301	      selectedIdRef.current = near.id;
302	      setSelectedId(near.id);
303	      dragRef.current = { id: near.id, startMouseX: x, startMouseY: y, origX: near.x, origY: near.y, moved: false };
